  "Binary Dynamics": { ja: "連星ダイナミクス", ko: "쌍성 동역학", de: "Binärdynamik", fr: "Dynamique binaire", es: "Dinámica binaria", it: "Dinamica binaria" },
  "No companion configured — ": { ja: "伴星が未設定 — ", ko: "동반성 미설정 — ", de: "Kein Begleiter konfiguriert — ", fr: "Aucun compagnon configuré — ", es: "Sin compañera configurada — ", it: "Nessuna compagna configurata — " },
  "switch to the ": { ja: "上の §01 の ", ko: "위 §01 의 ", de: "wechseln Sie oben in §01 zum Reiter ", fr: "passez à l'onglet ", es: "cambia a la pestaña ", it: "passa alla scheda " },
  " tab in §01 above to build a binary system": { ja: " タブで連星系を構築", ko: " 탭으로 쌍성계 구성", de: " in §01, um ein Binärsystem aufzubauen", fr: " dans §01 ci-dessus pour construire un système binaire", es: " en §01 arriba para crear un sistema binario", it: " in §01 sopra per costruire un sistema binario" },
  "chirp Mc": { ja: "チャープ質量 Mc", ko: "처프 질량 Mc", de: "Chirp-Masse Mc", fr: "masse de chirp Mc", es: "masa de chirp Mc", it: "massa di chirp Mc" },
  "Chirp Mc": { ja: "チャープ質量 Mc", ko: "처프 질량 Mc", de: "Chirp-Masse Mc", fr: "Masse de chirp Mc", es: "Masa de chirp Mc", it: "Massa di chirp Mc" },
