  "Inspiral progress · d/d₀": { ja: "インスパイラル進行 · d/d₀", ko: "인스파이럴 진행 · d/d₀", de: "Inspiral-Fortschritt · d/d₀", fr: "progression spirale · d/d₀", es: "progreso de espiral · d/d₀", it: "avanzamento spirale · d/d₀" },
  "Inspiral progress": { ja: "インスパイラル進行", ko: "인스파이럴 진행", de: "Inspiral-Fortschritt", fr: "progression spirale", es: "progreso de espiral", it: "avanzamento spirale" },
  " Double black hole → inspirals until the horizons touch and merge.": { ja: " 連星ブラックホール → 地平面が接触し合体するまでインスパイラル。", ko: " 쌍성 블랙홀 → 지평선이 닿아 병합할 때까지 인스파이럴.", de: " Doppeltes Schwarzes Loch → Inspiral bis die Horizonte sich berühren und verschmelzen.", fr: " Trou noir double → spirale jusqu'à ce que les horizons se touchent et fusionnent.", es: " Agujero negro doble → espiral hasta que los horizontes se tocan y se fusionan.", it: " Doppio buco nero → spirale finché gli orizzonti si toccano e si fondono." },
  " Includes a non-BH member → inspirals until the surfaces make contact.": { ja: " 非 BH 成員を含む → 表面が接触するまでインスパイラル。", ko: " 비 BH 구성원 포함 → 표면이 접촉할 때까지 인스파이럴.", de: " Enthält ein Nicht-BH-Mitglied → Inspiral bis die Oberflächen Kontakt haben.", fr: " Comprend un membre non-BH → spirale jusqu'au contact des surfaces.", es: " Incluye un miembro no BH → espiral hasta que las superficies hacen contacto.", it: " Include un membro non BH → spirale finché le superfici entrano in contatto." },
  "MERGER COMPLETE": { ja: "合体完了", ko: "병합 완료", de: "VERSCHMELZUNG ABGESCHLOSSEN", fr: "FUSION TERMINÉE", es: "FUSIÓN COMPLETA", it: "FUSIONE COMPLETATA" },
  "Merger complete": { ja: "合体完了", ko: "병합 완료", de: "Verschmelzung abgeschlossen", fr: "Fusion terminée", es: "Fusión completa", it: "Fusione completata" },
  "Binary engine not initialised.": { ja: "連星エンジンが未初期化です。", ko: "쌍성 엔진이 초기화되지 않았습니다.", de: "Binär-Engine nicht initialisiert.", fr: "Moteur binaire non initialisé.", es: "Motor binario no inicializado.", it: "Motore binario non inizializzato." },
  "Binary · INSPIRAL ACTIVE": { ja: "連星 · インスパイラル稼働中", ko: "쌍성 · 인스파이럴 활성", de: "Binär · INSPIRAL AKTIV", fr: "Binaire · SPIRALE ACTIVE", es: "Binario · ESPIRAL ACTIVA", it: "Binario · SPIRALE ATTIVA" },
  "Activate binary companion": { ja: "連星の伴星を有効化", ko: "쌍성 동반성 활성화", de: "Binärbegleiter aktivieren", fr: "Activer le compagnon binaire", es: "Activar compañera binaria", it: "Attiva compagna binaria" },
  "Companion mass": { ja: "伴星質量", ko: "동반성 질량", de: "Begleitermasse", fr: "Masse du compagnon", es: "Masa de la compañera", it: "Massa della compagna" },
